class UserSession:
    """Simple user session manager."""

    @staticmethod
    def create_session(user_data):
        """Store user data in the Flask session."""
        session["saml_authenticated"] = True
        session["saml_name_id"] = user_data.get("name_id")
        session["saml_email"] = user_data.get("email")
        session["saml_first_name"] = user_data.get("first_name")
        session["saml_last_name"] = user_data.get("last_name")
        session["saml_display_name"] = user_data.get("display_name")
        session["saml_groups"] = user_data.get("groups", [])
        session["saml_session_index"] = user_data.get("session_index")
        session["saml_attributes"] = user_data.get("attributes", {})
        session["saml_auth_time"] = datetime.now(timezone.utc).isoformat()

    @staticmethod
    def is_authenticated():
        return session.get("saml_authenticated", False)

    @staticmethod
    def get_user():
        if not UserSession.is_authenticated():
            return None
        return {
            "name_id": session.get("saml_name_id"),
            "email": session.get("saml_email"),
            "first_name": session.get("saml_first_name"),
            "last_name": session.get("saml_last_name"),
            "display_name": session.get("saml_display_name"),
            "groups": session.get("saml_groups", []),
            "session_index": session.get("saml_session_index"),
            "attributes": session.get("saml_attributes", {}),
            "auth_time": session.get("saml_auth_time"),
        }

    @staticmethod
    def destroy_session():
        session.clear()


