@app.route("/")
def index():
    """Home page - redirect to profile if authenticated, else show login."""
    if UserSession.is_authenticated():
        return redirect("/profile")
    return render_template_string(LOGIN_PAGE, error=request.args.get("error"))


@app.route("/profile")
def profile():
    """Protected profile page."""
    user = UserSession.get_user()
    if not user:
        return redirect("/")
    return render_template_string(PROFILE_PAGE, user=user)


@app.route("/saml/login")
def saml_login():
    """Initiate SAML authentication by redirecting to the IdP."""
    try:
        relay_state = request.args.get("next", "/profile")
        redirect_url, request_id = saml_sp.create_authn_request(
            relay_state=relay_state
        )
        # Store the request ID for InResponseTo validation
        session["saml_request_id"] = request_id
        return redirect(redirect_url)
    except SAMLError as e:
        return redirect(f"/?error={str(e)}")


