def saml_acs():
    """
    Assertion Consumer Service (ACS) endpoint.
    Receives and processes the SAML response from the IdP.
    """
    saml_response = request.form.get("SAMLResponse")
    relay_state = request.form.get("RelayState", "/profile")

    if not saml_response:
        return redirect("/?error=No SAMLResponse received")

    try:
        # Process the SAML response
        user_data = saml_sp.process_response(saml_response)

        # Create user session
        UserSession.create_session(user_data)

        # Log successful authentication
        app.logger.info(
            f"SAML authentication successful for user: {user_data.get('email')}"
        )

        return redirect(relay_state)

    except SAMLError as e:
        app.logger.error(f"SAML authentication failed: {e}")
        return redirect(f"/?error={str(e)}")
    except Exception as e:
        app.logger.exception(f"Unexpected error during SAML processing: {e}")
        return redirect("/?error=An unexpected error occurred during authentication")


@app.route("/saml/logout")
def saml_logout():
    """Logout the user and optionally initiate SLO."""
    UserSession.destroy_session()
    return redirect("/")


@app.route("/saml/sls", methods=["GET", "POST"])
def saml_sls():
    """Single Logout Service endpoint."""
    UserSession.destroy_session()
    return redirect("/")


@app.route("/saml/metadata")
def saml_metadata():
    """Serve SP metadata for IdP configuration."""
    metadata = saml_sp.generate_metadata()
    return app.response_class(
        response=metadata,
        status=200,
        mimetype="application/xml",
    )


@app.route("/api/user")
def api_user():
    """API endpoint to get current user info as JSON."""
    user = UserSession.get_user()
    if not user:
        return jsonify({"authenticated": False}), 401
    return jsonify({"authenticated": True, "user": user})


